class Solution {
public:
    bool canTransform(string start, string result) {
        int m = start.length();
        int n = result.length();

        vector<vector<char>> dp(m + 1, vector<char>(n + 1));

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (start[i - 1] == result[j - 1]) {
                    dp[i][j] = dp[i - 1][j - 1];
                } else if (start[i - 1] == 'X') {
                    dp[i][j] = dp[i - 1][j];
                } else if (result[j - 1] == 'X') {
                    dp[i][j] = dp[i][j - 1];
                } else {
                    dp[i][j] = dp[i - 1][j - 1];
                }
            }
        }

        return dp[m][n] == 'X';
    }
};
